 * @param {string|number} r 
 * @param {string} directions 
 * @returns {number}
 */
function solve(l, r, directions) {

    /**
     * Checks if a sequence is non-decreasing.
     * @param {number[]} sequence 
     * @returns {boolean}
     */
    function isNonDecreasing(sequence) {
        for (let i = 0; i < sequence.length - 1; i++) {
            if (sequence[i] > sequence[i + 1]) {
                return false;
            }
        }
        return true;
    }

    /**
     * Simulates the grid filling and path traversal for a given number x.
     * @param {bigint} x_bigint 
     * @param {string} directions 
     * @returns {number[]} The path sequence.
     */
    function getGridAndPathSequence(x_bigint, directions) {
        // 1. Padding and Grid Filling
        let x_str = x_bigint.toString();
        // Pad to 16 digits
        let padded_x_str = x_str.padStart(16, '0');

        let grid = Array(4).fill(0).map(() => Array(4).fill(0));

        for (let i = 0; i < 16; i++) {
            const digit = parseInt(padded_x_str[i]);
            const r = Math.floor(i / 4);
            const c = i % 4;
            grid[r][c] = digit;
        }

        // 2. Path Traversal
        let path_sequence = [];

        // Start at (0, 0)
        let r = 0;
        let c = 0;

        // Record starting element
        path_sequence.push(grid[r][c]);

        // Apply 6 directions
        for (let i = 0; i < 6; i++) {
            const direction = directions[i];

            if (direction === 'D') {
                r += 1;
            } else if (direction === 'R') {
                c += 1;
            }

            // The constraints guarantee the path stays within bounds [0, 3] x [0, 3]

            // Record the digit at the new position
            path_sequence.push(grid[r][c]);
        }

        return path_sequence;
    }

    let count = 0;

    // Convert L and R to BigInts to handle numbers up to 9*10^15 safely
    let L = BigInt(l);
    let R = BigInt(r);

    for (let x = L; x <= R; x++) {
        const sequence = getGridAndPathSequence(x, directions);
        if (isNonDecreasing(sequence)) {
            count++;
        }
    }

    return count;
}

