function solve(l: number, r: number, directions: string): number {

    // --- Step 1: Precalculate Target Indices K ---
    // K[i] stores the index (0-15) in the 16-digit padded number corresponding to the i-th step digit d_i.
    const K: number[] = new Array(7);
    let r_coord = 0;
    let c_coord = 0;
    K[0] = 0; // Starting position (0, 0) -> index 0

    for (let i = 0; i < 6; i++) {
        const direction = directions[i];

        if (direction === 'D') {
            r_coord += 1;
        } else if (direction === 'R') {
            c_coord += 1;
        }

        // Index = row * 4 + col
        const index = r_coord * 4 + c_coord;
        K[i + 1] = index;
    }

    // --- Step 2: Digit DP Implementation ---

    /**
     * Counts the number of good integers x such that 0 <= x <= N.
     * N must be passed as BigInt.
     * @param N_bigint The upper bound.
     * @returns The count of good numbers.
     */
    function countUpTo(N_bigint: bigint): number {
        if (N_bigint < 0n) return 0;

        // We are dealing with 16 digits padded representation.
        let N_str = N_bigint.toString().padStart(16, '0');
        const D = 16; // Total number of digits/positions

        // Memoization table: memo[position][tight][prev_d]
        // Position: 0..16 (17)
        // Tight: 0 or 1 (2)
        // Prev_d: 0..9 (10)
        // Since we use BigInt for counts, the memo stores numbers.
        const memo: Array<Array<Array<number | undefined>>> = 
            Array(D + 1).fill(0).map(() => 
                Array(2).fill(0).map(() => 
                    Array(10).fill(undefined)
                )
            );

        // DP function
        // p: current digit position (0 to 15)
        // tight: boolean, true if restricted by N_str
        // prev_d: the value of the last successfully placed required digit d_{i-1}. Range 0-9.
        // next_k_index: the index i in K (0..7) we are currently looking to satisfy (d_i).
        function dp(p: number, tight: boolean, prev_d: number, next_k_index: number): number {

            // Base Case: All 16 positions processed
            if (p === D) {
                // Success only if we have satisfied all 7 required digits (d0 to d6)
                return next_k_index === 7 ? 1 : 0;
            }

            // Check Memoization (Only if not tight, as tight depends on N_str)
            if (!tight) {
                const key = prev_d;
                if (memo[p][0][key] !== undefined) {
                    return memo[p][0][key]!;
                }
            }
            // Note: We don't memoize based on tight=true because the limit changes.

            const upper_bound = tight ? parseInt(N_str[p]) : 9;
            let count = 0;

            for (let digit = 0; digit <= upper_bound; digit++) {

                // Determine new state parameters
                const new_tight = tight && (digit === upper_bound);
                let new_prev_d = prev_d;
                let new_next_k_index = next_k_index;

                // Check if the current position p corresponds to the next required index K[next_k_index]
                if (next_k_index < 7 && p === K[next_k_index]) {

                    // Constraint check: The current required digit must be >= the previous required digit
                    if (digit >= prev_d) {
                        // Constraint met: Advance sequence index, update prev_d
                        new_prev_d = digit;
                        new_next_k_index += 1;
                    } else {
                        // Constraint failed: Skip this branch (digit cannot be chosen here)
                        continue;
                    }
                } 
                // If p is not K[next_k_index], the required sequence index and previous digit constraint remain unchanged.

                // Recurse
                count += dp(p + 1, new_tight, new_prev_d, new_next_k_index);
            }

            // Store result if not tight
            if (!tight) {
                memo[p][0][prev_d] = count;
            }

